function sliderEngineering() {
    var swiper = new Swiper('.engineering .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 90,
        speed: 500,
        pagination: {
            el: ".engineering .swiper-pagination",
            clickable: true,
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 30,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 40,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 90,
            }
        }
    })
}

