$(document).ready(function () {
    sliderEngineering();
    sliderArchitecture();
    sliderFormats();
    sliderNews();

    // Burger
    $('.burger').click(function () {
        $('.burger').toggleClass('burger--active')
        $('.header-menu').toggleClass('header-menu--active')
        $('body').toggleClass('fixed-body')
    })

    $('.header-menu__list li a').click(function () {
        $('.burger').removeClass('burger--active')
        $('.header-menu').removeClass('header-menu--active')
        $('body').removeClass('fixed-body')
    })

    // Fancybox
    Fancybox.bind("[data-fancybox]", {});

    // Select
    $('.nice-select').niceSelect();

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }
})

// Scroll
const plan = document.querySelector('.plan__wrap');
const planInner = document.querySelector('.plan__inner');

const scroll = document.querySelector('.scroll');
const scrollInner = document.querySelector('.scroll__inner');

function update() {
    scrollInner.style.width = planInner.scrollWidth + 'px';
}

update();
window.addEventListener('resize', update);

function syncScrollToPlan() {
    const maxPlan = plan.scrollWidth - plan.clientWidth;
    const maxScroll = scroll.scrollWidth - scroll.clientWidth;

    if (maxScroll <= 0) return;

    plan.scrollLeft = (scroll.scrollLeft / maxScroll) * maxPlan;
}

function syncPlanToScroll() {
    const maxPlan = plan.scrollWidth - plan.clientWidth;
    const maxScroll = scroll.scrollWidth - scroll.clientWidth;

    if (maxPlan <= 0) return;

    scroll.scrollLeft = (plan.scrollLeft / maxPlan) * maxScroll;
}

scroll.addEventListener('scroll', syncScrollToPlan);
plan.addEventListener('scroll', syncPlanToScroll);